function dispatchTask(input) {
  return Effect.gen(function* () {
    const { taskId, projectSlug } = validateInput(DispatchTaskSchema, input);
    const workerQueueDb = yield* WorkerQueueDbTag;
    const taskDomainService = yield* TaskDomainService;
    const task = yield* taskDomainService.findById(taskId);
    if (!task) {
      return yield* Effect.fail(new EntityNotFoundError("Task", taskId));
    }
    if (task.status !== "BACKLOG" && task.status !== "READY") {
      return yield* Effect.fail(new BusinessRuleError(`Task cannot be dispatched: status is ${task.status}. Only BACKLOG or READY tasks can be dispatched.`));
    }
    const existing = getQueueEntryWithWorker(workerQueueDb, taskId);
    if (existing) {
      const workerSummary2 = workerQueueDb.getWorkerSummary(DEFAULT_HEARTBEAT_THRESHOLD_SECONDS);
      return {
        success: true,
        alreadyQueued: true,
        message: existing.worker ? `Task already queued and claimed by ${existing.worker.name}` : "Task already queued, waiting for a worker",
        queueEntry: existing.entry,
        claimedByWorker: existing.worker,
        workerSummary: workerSummary2
      };
    }
    workerQueueDb.enqueue(taskId, projectSlug);
    const result = getQueueEntryWithWorker(workerQueueDb, taskId);
    if (!result) {
      return yield* Effect.fail(new BusinessRuleError("Failed to enqueue task: entry not found after enqueue"));
    }
    const workerSummary = workerQueueDb.getWorkerSummary(DEFAULT_HEARTBEAT_THRESHOLD_SECONDS);
    return {
      success: true,
      alreadyQueued: false,
      message: "Task dispatched to queue",
      queueEntry: result.entry,
      claimedByWorker: result.worker,
      workerSummary
    };
  });
}

